blocks.body:
{
    "level": "B2–C1",
    "intro": "W tym temacie dowiesz się, jak <strong>styl i formalność</strong> wpływają na wybór pomiędzy stroną aktywną a pasywną oraz kiedy użycie strony biernej jest <strong>właściwe</strong>, a kiedy <strong>niepożądane</strong>.",
    "rules": [
        {
            "label": "Formalny",
            "color": "emerald",
            "text": "Strona bierna nadaje tekstowi <strong>formalność i obiektywność</strong>:",
            "example": "The experiment was conducted in 2023."
        },
        {
            "label": "Naukowy",
            "color": "blue",
            "text": "W <strong>tekstach naukowych</strong> strona bierna jest normą:",
            "example": "The data were analyzed using SPSS."
        },
        {
            "label": "Potoczny",
            "color": "amber",
            "text": "W <strong>języku mówionym</strong> strona aktywna brzmi bardziej naturalnie:",
            "example": "We analyzed the data. (не: The data were analyzed by us)"
        }
    ]
}

{
    "title": "1. Gdzie strona bierna jest typowa i odpowiednia",
    "sections": [
        {
            "label": "Teksty naukowe",
            "color": "emerald",
            "description": "W <strong>artykułach naukowych</strong> i opracowaniach:",
            "examples": [
                {
                    "en": "The experiment was conducted under controlled conditions.",
                    "ua": "Eksperyment przeprowadzono w kontrolowanych warunkach."
                },
                {
                    "en": "The samples were collected from five locations.",
                    "ua": "Próbki pobrano z pięciu lokalizacji."
                },
                {
                    "en": "It was observed that temperature affects the results.",
                    "ua": "Stwierdzono, że temperatura ma wpływ na wyniki."
                }
            ]
        },
        {
            "label": "Oficjalne dokumenty",
            "color": "blue",
            "description": "W <strong>prawach, umowach, instrukcjach</strong>:",
            "examples": [
                {
                    "en": "Smoking is prohibited in this area.",
                    "ua": "Na tym obszarze palenie jest zabronione."
                },
                {
                    "en": "Applications must be submitted by Friday.",
                    "ua": "Zgłoszenia należy nadsyłać do piątku."
                },
                {
                    "en": "This contract is governed by UK law.",
                    "ua": "Niniejsza umowa podlega prawu brytyjskiemu."
                }
            ]
        },
        {
            "label": "Wiadomości i media",
            "color": "amber",
            "description": "W <strong>wiadomościach</strong>:",
            "examples": [
                {
                    "en": "The suspect was arrested yesterday.",
                    "ua": "Podejrzany został wczoraj zatrzymany."
                },
                {
                    "en": "The new law has been approved.",
                    "ua": "Nowe prawo zostało zatwierdzone."
                },
                {
                    "en": "Several people were injured in the accident.",
                    "ua": "W wypadku rannych zostało kilka osób."
                }
            ]
        },
        {
            "label": "Instrukcje techniczne",
            "color": "rose",
            "description": "W <strong>dokumentacji technicznej</strong>:",
            "examples": [
                {
                    "en": "The device should be charged for 2 hours.",
                    "ua": "Urządzenie należy ładować przez 2 godziny."
                },
                {
                    "en": "Cookies are used to improve user experience.",
                    "ua": "Pliki cookie służą do poprawy komfortu użytkowania."
                },
                {
                    "en": "Updates are installed automatically.",
                    "ua": "Aktualizacje są instalowane automatycznie."
                }
            ]
        }
    ]
}

{
    "title": "2. Styl formalny i nieformalny",
    "intro": "Porównywanie tej samej wiadomości w różnych stylach:",
    "rows": [
        {
            "en": "Formal: The report was submitted on time.",
            "ua": "Raport został złożony w terminie.",
            "note": "Oficjalny dokument, e-mail."
        },
        {
            "en": "Informal: I submitted the report on time.",
            "ua": "Złożyłem raport w terminie.",
            "note": "Rozmowa z kolegą."
        },
        {
            "en": "Formal: Mistakes were made.",
            "ua": "Popełniono błędy.",
            "note": "Oficjalne oświadczenie (bez wskazania sprawcy)."
        },
        {
            "en": "Informal: We made mistakes.",
            "ua": "Popełniliśmy błędy.",
            "note": "Uznanie odpowiedzialności."
        }
    ],
    "warning": "📌 Pasywnej można użyć, aby uniknąć odpowiedzialności lub winy!"
}

{
    "title": "3. Kiedy lepiej unikać strony biernej",
    "sections": [
        {
            "label": "Język mówiony",
            "color": "rose",
            "description": "W <strong>codziennej komunikacji</strong> głos bierny brzmi nienaturalnie:",
            "examples": [
                {
                    "en": "Unnatural: The ball was kicked by John.",
                    "ua": "Nienaturalne: Piłka została uderzona przez Johna."
                },
                {
                    "en": "Natural: John kicked the ball.",
                    "ua": "Naturalnie: John uderzył piłkę."
                }
            ]
        },
        {
            "label": "Kiedy wykonawca jest ważny",
            "color": "amber",
            "description": "Jeśli <strong>istnieje znaczenie, kto wykonał czynność</strong>:",
            "examples": [
                {
                    "en": "Awkward: The book was written by Shakespeare.",
                    "ua": "Zbędna strona bierna dla znanego autora."
                },
                {
                    "en": "Better: Shakespeare wrote the book.",
                    "ua": "Lepiej: Szekspir napisał książkę."
                }
            ]
        },
        {
            "label": "Nadmierna bierność",
            "color": "blue",
            "description": "Za dużo pasywności <strong>męczy czytelnika</strong>:",
            "examples": [
                {
                    "en": "Too much passive: The report was written, was reviewed, and was submitted.",
                    "ua": "Przeciążony pasywnym."
                },
                {
                    "en": "Better: We wrote, reviewed, and submitted the report.",
                    "ua": "Lepiej: Napisaliśmy, sprawdziliśmy i złożyliśmy raport."
                }
            ]
        }
    ]
}

{
    "title": "4. Bądź pasywny vs bądź bierny ze względów formalnych",
    "intro": "Wybór pomiędzy <strong>be</strong> i <strong>get</strong> zależy od stylu:",
    "items": [
        {
            "label": "być + V3",
            "title": "Formalny, neutralny",
            "subtitle": "Dokument został podpisany. (oficjalnie)"
        },
        {
            "label": "zdobądź + V3",
            "title": "Nieformalny, konwersacyjny",
            "subtitle": "Dokument został podpisany. (potoczny)"
        },
        {
            "label": "Teksty naukowe",
            "title": "Tylko bądź pasywny",
            "subtitle": "Dane zostały przeanalizowane. ✅"
        },
        {
            "label": "Codzienne nadawanie",
            "title": "Get-passive jest prawidłowe",
            "subtitle": "Awansował! (pozytywna wiadomość)"
        }
    ]
}

{
    "title": "5. Efekty stylistyczne strony biernej",
    "sections": [
        {
            "label": "Obiektywność",
            "color": "emerald",
            "description": "Strona bierna sprawia wrażenie <strong>obiektywizmu i bezstronności</strong>:",
            "examples": [
                {
                    "en": "It is believed that climate change is accelerating.",
                    "ua": "Uważa się, że zmiany klimatyczne przyspieszają."
                },
                {
                    "en": "The results were verified independently.",
                    "ua": "Wyniki zostały niezależnie zweryfikowane."
                }
            ]
        },
        {
            "label": "Depersonalizacja",
            "color": "blue",
            "description": "Strona bierna <strong>ukrywa wykonawcę</strong> (czasami celowo):",
            "examples": [
                {
                    "en": "Mistakes were made.",
                    "ua": "Popełniono błędy. (który jest nieznany)"
                },
                {
                    "en": "It has been decided to close the factory.",
                    "ua": "Podjęto decyzję o zamknięciu zakładu. (kto zdecydował?)"
                }
            ]
        },
        {
            "label": "Skoncentruj się na działaniu/przedmiocie",
            "color": "amber",
            "description": "Strona bierna <strong>podkreśla akcję lub wynik</strong>:",
            "examples": [
                {
                    "en": "The Mona Lisa was painted in the early 16th century.",
                    "ua": "Mona Lisa została namalowana na początku XVI wieku."
                },
                {
                    "en": "The building was destroyed in the fire.",
                    "ua": "Budynek został zniszczony przez pożar."
                }
            ]
        }
    ]
}

{
    "title": "6. Styl akademicki: zalecenia",
    "intro": "Współczesne zalecenia dotyczące strony biernej w tekstach akademickich:",
    "rows": [
        {
            "en": "Traditional: The results were analyzed.",
            "ua": "Tradycyjnie: biernie w metodologii.",
            "note": "Nadal szeroko stosowany."
        },
        {
            "en": "Modern: We analyzed the results.",
            "ua": "Teraźniejszość: aktywna z „my”.",
            "note": "Polecane przez wiele magazynów."
        },
        {
            "en": "Mixed: The samples were collected. We analyzed them.",
            "ua": "Styl mieszany.",
            "note": "Równowaga obiektywności i przejrzystości."
        }
    ],
    "warning": "📌 Sprawdź wymagania konkretnego czasopisma lub instytucji!"
}

{
    "title": "7. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Get-passive w tekście formalnym.",
            "wrong": "The experiment got conducted.",
            "right": "✅ The experiment was conducted."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Nadmierna bierność bez potrzeby.",
            "wrong": "The ball was kicked by John to Mary.",
            "right": "✅ John kicked the ball to Mary."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Pasywny z oczywistym sprawcą.",
            "wrong": "I was asked a question by the teacher.",
            "right": "✅ The teacher asked me a question."
        },
        {
            "label": "Błąd 4",
            "color": "rose",
            "title": "Pasywny w nieformalnym kontekście.",
            "wrong": "A good time was had by all at the party.",
            "right": "✅ Everyone had a good time at the party."
        }
    ]
}
